package configserver

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strings"

	"github.com/nhost/be/services/mimir/graph"
	"github.com/nhost/be/services/mimir/model"
	"github.com/nhost/nhost/cli/project/env"
	"github.com/pelletier/go-toml/v2"
	"github.com/sirupsen/logrus"
)

const zeroUUID = "00000000-0000-0000-0000-000000000000"

var ErrNotImpl = errors.New("not implemented")

type Local struct {
	// we use paths instead of readers/writers because the intention is that these
	// files will be mounted as volumes in a container and if the file is changed
	// outside of the container, the filedescriptor might just be pointing to the
	// old file.
	config      string
	secrets     string
	runServices map[string]string
}

func NewLocal(config, secrets string, runServices map[string]string) *Local {
	return &Local{
		config:      config,
		secrets:     secrets,
		runServices: runServices,
	}
}

func unmarshal[T any](config any) (*T, error) {
	b, err := json.Marshal(config)
	if err != nil {
		return nil, fmt.Errorf("problem marshaling cue value: %w", err)
	}

	var cfg T
	if err := json.Unmarshal(b, &cfg); err != nil {
		return nil, fmt.Errorf("problem unmarshaling cue value: %w", err)
	}

	return &cfg, nil
}

func (l *Local) GetServices(runServices map[string]string) (graph.Services, error) {
	services := make(graph.Services, 0, len(runServices))
	for id, r := range runServices {
		b, err := os.ReadFile(r)
		if err != nil {
			return nil, fmt.Errorf("failed to read run service file: %w", err)
		}

		var cfg model.ConfigRunServiceConfig
		if err := toml.Unmarshal(b, &cfg); err != nil {
			return nil, fmt.Errorf("failed to unmarshal run service config: %w", err)
		}

		services = append(services, &graph.Service{
			ServiceID: id,
			Config:    &cfg,
		})
	}

	return services, nil
}

func (l *Local) GetApps(
	configFile, secretsFile string, runServicesFiles map[string]string,
) ([]*graph.App, error) {
	b, err := os.ReadFile(configFile)
	if err != nil {
		return nil, fmt.Errorf("failed to read config file: %w", err)
	}

	var rawCfg any
	if err := toml.Unmarshal(b, &rawCfg); err != nil {
		return nil, fmt.Errorf("failed to unmarshal config: %w", err)
	}

	cfg, err := unmarshal[model.ConfigConfig](rawCfg)
	if err != nil {
		return nil, fmt.Errorf("failed to fill config: %w", err)
	}

	b, err = os.ReadFile(secretsFile)
	if err != nil {
		return nil, fmt.Errorf("failed to read secrets file: %w", err)
	}

	var secrets model.Secrets
	if err := env.Unmarshal(b, &secrets); err != nil {
		return nil, fmt.Errorf(
			"failed to parse secrets, make sure secret values are between quotes: %w",
			err,
		)
	}

	services, err := l.GetServices(runServicesFiles)
	if err != nil {
		return nil, fmt.Errorf("failed to get services: %w", err)
	}

	pgMajorVersion := "14"
	if cfg.GetPostgres().GetVersion() != nil {
		pgMajorVersion = strings.Split(*cfg.GetPostgres().GetVersion(), ".")[0]
	}

	return []*graph.App{
		{
			Config: cfg,
			SystemConfig: &model.ConfigSystemConfig{ //nolint:exhaustruct
				Postgres: &model.ConfigSystemConfigPostgres{ //nolint:exhaustruct
					MajorVersion: &pgMajorVersion,
					Database:     "local",
					ConnectionString: &model.ConfigSystemConfigPostgresConnectionString{
						Backup:  "a",
						Hasura:  "a",
						Auth:    "a",
						Storage: "a",
					},
				},
			},
			Secrets:  secrets,
			Services: services,
			AppID:    zeroUUID,
		},
	}, nil
}

func (l *Local) CreateApp(_ context.Context, _ *graph.App, _ logrus.FieldLogger) error {
	return ErrNotImpl
}

func (l *Local) DeleteApp(_ context.Context, _ *graph.App, _ logrus.FieldLogger) error {
	return ErrNotImpl
}

func (l *Local) UpdateConfig(_ context.Context, _, newApp *graph.App, _ logrus.FieldLogger) error {
	b, err := toml.Marshal(newApp.Config)
	if err != nil {
		return fmt.Errorf("failed to marshal app config: %w", err)
	}

	if err := os.WriteFile(l.config, b, 0o644); err != nil { //nolint:gosec,mnd
		return fmt.Errorf("failed to write config: %w", err)
	}

	return nil
}

func (l *Local) UpdateSystemConfig(_ context.Context, _, _ *graph.App, _ logrus.FieldLogger) error {
	return ErrNotImpl
}

func (l *Local) UpdateSecrets(_ context.Context, _, newApp *graph.App, _ logrus.FieldLogger) error {
	m := make(map[string]string)
	for _, v := range newApp.Secrets {
		m[v.Name] = v.Value
	}

	b, err := toml.Marshal(m)
	if err != nil {
		return fmt.Errorf("failed to marshal app secrets: %w", err)
	}

	if err := os.WriteFile(l.secrets, b, 0o644); err != nil { //nolint:gosec,mnd
		return fmt.Errorf("failed to write secrets: %w", err)
	}

	return nil
}

func (l *Local) CreateRunServiceConfig(
	_ context.Context, _ string, _ *graph.Service, _ logrus.FieldLogger,
) error {
	return ErrNotImpl
}

func (l *Local) UpdateRunServiceConfig(
	_ context.Context, _ string, _, newSvc *graph.Service, _ logrus.FieldLogger,
) error {
	wr, ok := l.runServices[newSvc.ServiceID]
	if !ok {
		return fmt.Errorf("run service not found: %s", newSvc.ServiceID) //nolint:err113
	}

	b, err := toml.Marshal(newSvc.Config)
	if err != nil {
		return fmt.Errorf("failed to marshal run service config: %w", err)
	}

	if err := os.WriteFile(wr, b, 0o644); err != nil { //nolint:gosec,mnd
		return fmt.Errorf("failed to write run service config: %w", err)
	}

	return nil
}

func (l *Local) DeleteRunServiceConfig(
	_ context.Context, _ string, _ *graph.Service, _ logrus.FieldLogger,
) error {
	return ErrNotImpl
}

func (l *Local) ChangeDatabaseVersion(
	_ context.Context,
	_, _ *graph.App,
	_ logrus.FieldLogger,
) error {
	return ErrNotImpl
}

package middleware

import (
	"net/http"
	"slices"
	"strings"

	"github.com/gin-gonic/gin"
)

// CORSOptions configures the CORS middleware behavior.
//
// The middleware supports three strategies for handling Access-Control-Allow-Headers:
//   - nil (default): Reflects the Access-Control-Request-Headers from the client
//   - empty slice: Denies all headers (no Access-Control-Allow-Headers header is set)
//   - non-empty slice: Uses the specified headers
type CORSOptions struct {
	// AllowedOrigins is a list of origins permitted to make cross-origin requests.
	// Use "*" or nil slice to allow all origins.
	AllowedOrigins []string

	// AllowedMethods is a list of HTTP methods the client is permitted to use.
	// Common values: GET, POST, PUT, DELETE, PATCH, OPTIONS.
	AllowedMethods []string

	// AllowedHeaders controls which headers clients can use in requests.
	// - nil: reflects client's Access-Control-Request-Headers (permissive)
	// - empty slice: denies all headers
	// - non-empty: allows only specified headers
	AllowedHeaders []string

	// ExposedHeaders lists headers that browsers are allowed to access.
	// By default, browsers only expose simple response headers.
	ExposedHeaders []string

	// AllowCredentials indicates whether the request can include credentials
	// (cookies, authorization headers, or TLS client certificates).
	AllowCredentials bool

	// MaxAge indicates how long (in seconds) the results of a preflight request
	// can be cached. Empty string means no caching directive is sent.
	MaxAge string
}

// CORS returns a Gin middleware handler that implements Cross-Origin Resource Sharing (CORS).
//
// The middleware handles both preflight (OPTIONS) requests and actual requests, setting
// appropriate CORS headers based on the provided configuration. It automatically adds
// the "Vary: Origin, Access-Control-Request-Method" header for proper cache behavior.
//
// For preflight requests (OPTIONS), the middleware responds with 204 No Content and
// prevents further request processing. For actual requests, it sets CORS headers and
// continues the middleware chain.
//
// Example usage:
//
//	router.Use(middleware.CORS(middleware.CORSOptions{
//		AllowedOrigins:   []string{"https://example.com", "https://app.example.com"},
//		AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE"},
//		AllowedHeaders:   nil, // reflects client headers
//		AllowCredentials: true,
//		MaxAge:           "3600",
//	}))
func CORS(opts CORSOptions) gin.HandlerFunc { //nolint:cyclop,funlen
	allowedMethods := strings.Join(opts.AllowedMethods, ", ")
	exposedHeaders := strings.Join(opts.ExposedHeaders, ", ")

	allowCredentials := "false"
	if opts.AllowCredentials {
		allowCredentials = "true"
	}

	var (
		headerStrategy string // "reflect", "specific", or "deny"
		allowedHeaders string
	)
	switch {
	case opts.AllowedHeaders == nil:
		headerStrategy = "reflect"
	case len(opts.AllowedHeaders) == 0:
		headerStrategy = "deny"
	default:
		headerStrategy = "specific"
		allowedHeaders = strings.Join(opts.AllowedHeaders, ", ")
	}

	f := func(c *gin.Context, origin string) {
		if opts.AllowedOrigins != nil &&
			!slices.Contains(opts.AllowedOrigins, origin) &&
			!slices.Contains(opts.AllowedOrigins, "*") {
			return
		}

		c.Header("Access-Control-Allow-Origin", origin)
		c.Header("Access-Control-Allow-Methods", allowedMethods)

		// Handle allowed headers based on strategy
		switch headerStrategy {
		case "specific":
			c.Header("Access-Control-Allow-Headers", allowedHeaders)
		case "reflect":
			headers := c.Request.Header.Get("Access-Control-Request-Headers")
			if headers != "" {
				c.Header("Access-Control-Allow-Headers", headers)
			}
		case "deny":
			// Don't set the header at all
		}

		if exposedHeaders != "" {
			c.Header("Access-Control-Expose-Headers", exposedHeaders)
		}

		c.Header("Access-Control-Allow-Credentials", allowCredentials)

		if opts.MaxAge != "" {
			c.Header("Access-Control-Max-Age", opts.MaxAge)
		}

		c.Writer.Header().Add("Vary", "Origin, Access-Control-Request-Method")
	}

	return func(c *gin.Context) {
		origin := c.Request.Header.Get("Origin")
		if c.Request.Method == http.MethodOptions {
			f(c, origin)

			c.Header("Content-Length", "0")
			c.AbortWithStatus(http.StatusNoContent)

			return
		}

		if origin != "" {
			f(c, origin)
		}

		c.Next()
	}
}

