				Name:    "logs",
				TLS:     useTLS,
				Rule:    traefikHostMatch("dashboard") + "&& PathPrefix(`/v1/logs`)",
				Port:    configserverPort,
				Rewrite: nil,
			},
		}.Labels(),
		Networks:   nil,
		Ports:      []Port{},
		Restart:    "always",
		Volumes:    volumes,
		WorkingDir: nil,
	}, nil
}

